const express = require('express');
const app = express();
const port = 3000;

// Secure input validation function
function sanitizeInput(input) {
  if (typeof input !== 'string') {
    return '';
  }
  
  // Remove potentially dangerous characters for log injection
  return input
    .replace(/[^\w\s\-\.\(\)\[\]\{\}\:\,\;\!\?\@\#\$\%\^\&\*\+\=\<\>\|\/\\]/g, '')
    .substring(0, 255); // Limit length
}

// Middleware to validate action parameter
const validateAction = (req, res, next) => {
  const action = req.query.action;
  
  if (!action) {
    return res.status(400).json({ error: 'Action parameter is required' });
  }
  
  const sanitizedAction = sanitizeInput(action);
  
  if (sanitizedAction !== action) {
    return res.status(400).json({ error: 'Invalid action characters' });
  }
  
  req.sanitizedAction = sanitizedAction;
  next();
};

// Log user activity with timestamp
const logUserActivity = (action, ip = 'unknown') => {
  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] User action from ${ip}: ${action}`);
};

// Route to log user activity
app.get('/log', validateAction, (req, res) => {
  const ip = req.ip || req.connection.remoteAddress || req.socket.remoteAddress;
  logUserActivity(req.sanitizedAction, ip);
  res.json({ message: 'Action logged successfully' });
});

app.listen(port, () => {
  console.log(`Audit trail server running at http://localhost:${port}`);
});